<template><div class="mgr"><h2>📦 库存管理</h2><el-table :data="list" stripe size="small"><el-table-column prop="code" label="编码"/><el-table-column prop="name" label="产品" min-width="140"/><el-table-column prop="quantity" label="库存"/><el-table-column label="状态"><template #default="{row}"><el-tag :type="row.quantity<=row.min_quantity?'danger':'success'" size="small">{{ row.quantity<=row.min_quantity?'低库存':'正常' }}</el-tag></template></el-table-column><el-table-column label="操作"><template #default="{row}"><el-button size="small" @click="adjProduct=row;show=true">调整</el-button></template></el-table-column></el-table><el-dialog v-model="show" title="库存调整" width="350px"><el-form label-width="60px"><el-form-item label="产品"><b>{{ adjProduct?.name }}</b></el-form-item><el-form-item label="操作"><el-radio-group v-model="type"><el-radio value="入库">入库</el-radio><el-radio value="出库">出库</el-radio></el-radio-group></el-form-item><el-form-item label="数量"><el-input-number v-model="qty" :min="1" style="width:100%"/></el-form-item></el-form><template #footer><el-button @click="show=false">取消</el-button><el-button type="primary" @click="doAdj">确认</el-button></template></el-dialog></div></template>
<script setup>import {ref,onMounted} from 'vue';import request from '@/utils/request';import {ElMessage} from 'element-plus';const list=ref([]);const show=ref(false);const adjProduct=ref(null);const type=ref('入库');const qty=ref(10);async function fetch(){try{list.value=await request.get('/inventory')||[]}catch{}}async function doAdj(){try{await request.post('/inventory/adjust',{productId:adjProduct.value.product_id,qty:type.value==='入库'?qty.value:-qty.value,type:type.value,remark:type.value});show.value=false;fetch();ElMessage.success('已调整')}catch{}}onMounted(fetch)</script>
<style scoped>.mgr{padding:0}</style>
